// JSX (what you write)
const element = <h1 className="greeting">Hello!</h1>;

// What it compiles to (what JavaScript sees)
const element = React.createElement(
  'h1',
  { className: 'greeting' },
  'Hello!'
);

// You write JSX. Babel transforms it. React renders it!

After compilation, JSX becomes regular JavaScript objects. This means you can:

```javascript
// Use JSX in variables
const greeting = <h1>Hello!</h1>;

// Return JSX from functions
function createGreeting() {
  return <p>Welcome!</p>;
}

// Pass JSX as arguments
render(component, <App />);

// Use JSX in conditionals
isLoggedIn ? <Dashboard /> : <Login />;
```

const user = {
  name: "Bob",
  age: 30,
  isActive: true
};

function Profile() {
  return (
    <div className="profile">
      {/* Embed variables */}
      <h2>{user.name}</h2>

      {/* Do calculations */}
      <p>Age in months: {user.age * 12}</p>

      {/* Conditional rendering */}
      {user.isActive && <span>Active User</span>}

      {/* Call functions */}
      <p>Name length: {user.name.length}</p>

      {/* Access properties */}
      <p>First letter: {user.name[0]}</p>
    </div>
  );
}

You can only use **expressions** in curly braces, not **statements**:

```javascript
// ✅ Expressions (return values)
{count + 1}
{getName()}
{isLoggedIn ? 'Yes' : 'No'}

// ❌ Statements (don't return values)
{if (count > 0) { return 'Yes'; }}  // Won't work!
{for (let i = 0; i < 5; i++) {}}    // Won't work!
{var x = 5;}                         // Won't work!
```

**Solution:** Do statements outside JSX, then use the result inside!

