  const name = "Alice";
  const age = 25;

  return (
    <div {{className}}="profile">
      <h1>{{name}}</h1>
      <p>Age: {age}</p>
      <img src="/avatar.jpg" {{alt}}="Profile" />
      {{/* Show adult status */}}
      <p>Adult: {age >= 18 ? 'Yes' : 'No'}</p>
    </{{div}}>
