function ProductCard() {
  const productName = "Wireless Mouse";
  const price = 29.99;
  const inStock = true;

  return (
    <div className="product-card">
      <h3>{productName}</h3>
      <p>Price: ${price}</p>
      <p>Status: {inStock ? 'In Stock' : 'Out of Stock'}</p>
    </div>
  );
}
